    public class ChipConfig
    {
        public uint Var1 { get; set; }
        public uint Watchdog { get; set; }
        public uint Uart { get; set; }
        public uint BromPayloadAddr { get; set; }
        public uint DaPayloadAddr { get; set; }
        public uint PlPayloadAddr { get; set; }
        public uint CqdmaBase { get; set; }
        public uint ApDmaMem { get; set; }
        public uint SejBase { get; set; }
        public uint DxccBase { get; set; }
        public uint GcpuBase { get; set; }
        public string Name { get; set; } = "";
        public string Description { get; set; } = "";
        public ushort DaCode { get; set; }
        public (uint, uint)[] Blacklist { get; set; }
        public uint BlacklistCount { get; set; }
        public (uint, uint)? SendPtr { get; set; }
        public uint CtrlBuffer { get; set; }
        public uint CmdHandler { get; set; }
        public (uint, uint)? BromRegisterAccess { get; set; }
        public uint MeidAddr { get; set; }
        public uint SocIdAddr { get; set; }
        public uint ProvAddr { get; set; }
        public DAmodes DaMode { get; set; } = DAmodes.LEGACY;
        public string Loader { get; set; }
        public uint MiscLock { get; set; }
        public uint EfuseAddr { get; set; }
        public bool Has64Bit { get; set; }
        public bool Iot { get; set; }
    }

