        /// <summary>
        /// Look up ChipConfig by HW code.
        /// </summary>
        public static ChipConfig GetConfig(ushort hwCode)
        {
            if (HwConfig.TryGetValue(hwCode, out ChipConfig config))
                return config;

            // Return a default config for unknown chips
            return new ChipConfig
            {
                Name = $"Unknown_0x{hwCode:X4}",
                DaCode = hwCode,
                DaMode = DAmodes.XFLASH
            };
        }

        /// <summary>
        /// Get watchdog address and disable value.
        /// </summary>
        public static (uint addr, uint value) GetWatchdogAddr(ChipConfig config)
        {
            if (config.Watchdog != 0)
                return (config.Watchdog, 0x22000064);
            return (0x10007000, 0x22000064); // default
        }
    }
